import type { MetricsStore, MetricStoreName } from './metrics/store/types';
import type { LayoutViewStore } from './layout/types';

import { getContext } from './storage';

export function getRenderingTrustedTypesRegex() {
  return getContext().trustedTypesRegex;
}

export function getRenderingCriticalCss() {
  return getContext().criticalCss;
}

export function getRenderingIslands<T = unknown>() {
  return getContext().islands as T | undefined;
}

export function getRenderingMelidata<T = unknown>() {
  return getContext().melidata as T | undefined;
}

export function getRenderingMetrics<
  S extends MetricStoreName,
  P extends Record<string, unknown> = Record<string, unknown>,
>(name: S) {
  return getContext().metrics[name] as MetricsStore<P, P, P>[S];
}

export function getRenderingLayoutView<TScript = unknown, TStyle = unknown>() {
  return getContext().layoutView as LayoutViewStore<TScript, TStyle>;
}
